function bfsTraversal(graph, start) {
  const visited = new Set();
  const result = [];
  const queue = [start];

  while (queue.length) {
    const node = queue.shift();
    if (visited.has(node)) continue;
    visited.add(node);
    result.push(node);

    const neighbors = graph[node] || [];
    for (const next of neighbors) {
      if (!visited.has(next)) queue.push(next);
    }
  }

  return result;
}

IList<int> BfsTraversal(IList<IList<int>> graph, int start)
{
    var result = new List<int>();
    if (graph == null || start < 0 || start >= graph.Count) return result;

    var seen = new bool[graph.Count];
    var q = new Queue<int>();
    q.Enqueue(start);
    seen[start] = true;

    while (q.Count > 0)
    {
        int node = q.Dequeue();
        result.Add(node);

        foreach (int nei in graph[node])
        {
            if (nei < 0 || nei >= graph.Count || seen[nei]) continue;
            seen[nei] = true;
            q.Enqueue(nei);
        }
    }

    return result;
}

